// s01_agent_loop/Program.cs -- The Agent Loop
//
// The whole secret of an AI coding agent in one pattern:
//
//     while stop_reason == "tool_use":
//         response = LLM(messages, tools)
//         execute tools
//         append results
//
// +---------+    +-----+    +---------+
// |  User   |--->| LLM |--->|  Tool   |
// | prompt  |    |     |    | execute |
// +---------+    +--+--+    +----+----+
//                  ^             |
//                  | tool_result |
//                  +-------------+ (loop continues)
//
// This is the core loop: feed tool results back to the model
// until the model decides to stop. Production agents layer
// policy, hooks, and lifecycle controls on top.

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);
var tools = new ToolRegistry();

var workDir = Directory.GetCurrentDirectory();
BashTool.Register(tools, workDir);  // ← the only tool the agent has in s01

// ── The core pattern: a while loop that calls tools until the model stops ──
//    (the loop itself lives in AgentHarness.RunUntilDoneAsync)
var system = $"You are a coding agent at {workDir}. Use bash to solve tasks. Act, don't explain.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, tools, system)
{
    OnLog = Console.WriteLine,
};

Console.WriteLine("s01: Agent Loop");
Console.WriteLine("Type a task and press Enter. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms01 >> \u001b[0m");

// s02_tool_use/Program.cs -- Tool Use
//
// "Adding a tool means adding one handler" — the loop stays untouched;
// new tools register into the dispatch map.
//
// Compared to s01:
//   + BashTool  (carried forward)
//   + FileTools (NEW in s02: read_file, write_file, edit_file, glob)
//   + PathGuard (NEW in s02: prevents escaping the workspace)
//
// The agent loop in AgentHarness.RunUntilDoneAsync is unchanged.

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);
var tools = new ToolRegistry();

var workDir = Directory.GetCurrentDirectory();
BashTool.Register(tools, workDir);                    // from s01
FileTools.Register(tools, workDir);                   // NEW in s02

var system = $"You are a coding agent at {workDir}. Use tools to solve tasks. Act, don't explain.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, tools, system)
{
    OnLog = Console.WriteLine,
};

Console.WriteLine("s02: Tool Use — five tools in one dispatch map");
Console.WriteLine("Type a task and press Enter. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms02 >> \u001b[0m");

// s03_permission/Program.cs -- Permission System
//
// "Set boundaries first, then grant freedom" — three gates inserted
// before tool execution:
//
//     Gate 1: Hard deny list (rm -rf /, sudo, ...)
//     Gate 2: Rule matching (writes outside workspace? destructive cmd?)
//     Gate 3: User approval (pause and wait for confirmation)
//
// Only one decision is added to the agent loop — AgentHarness already
// calls agent.Permissions.Check(...) before invoking each tool.

using System.Text.Json;
using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Permissions;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);
var tools = new ToolRegistry();

var workDir = Directory.GetCurrentDirectory();
BashTool.Register(tools, workDir);                    // from s01
FileTools.Register(tools, workDir);                   // from s02

// NEW in s03: the three-gate permission pipeline
var denyList = new[] { "rm -rf /", "sudo", "shutdown", "reboot", "mkfs", "dd if=", "> /dev/sda" };
var rules = new List<PermissionRule>
{
    new()
    {
        Tools = new[] { "write_file", "edit_file" },
        Check = args =>
        {
            if (args.TryGetProperty("path", out var p) && p.ValueKind == JsonValueKind.String)
            {
                try { _ = PathGuard.SafePath(workDir, p.GetString() ?? ""); return null; }
                catch { return "Writing outside workspace"; }
            }
            return null;
        },
        Message = "Writing outside workspace",
    },
    new()
    {
        Tools = new[] { "bash" },
        Check = args =>
        {
            if (args.TryGetProperty("command", out var c) && c.ValueKind == JsonValueKind.String)
            {
                var cmd = c.GetString() ?? "";
                if (cmd.Contains("rm ", StringComparison.Ordinal) ||
                    cmd.Contains("> /etc/", StringComparison.Ordinal) ||
                    cmd.Contains("chmod 777", StringComparison.Ordinal))
                {
                    return "Potentially destructive command";
                }
            }
            return null;
        },
        Message = "Potentially destructive command",
    },
};

var system = $"You are a coding agent at {workDir}. All destructive operations require user approval.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, tools, system)
{
    OnLog = Console.WriteLine,
    Permissions = new InteractivePermissionPipeline(workDir, denyList, rules),
};

Console.WriteLine("s03: Permission — three gates before every tool call");
Console.WriteLine("Type a task and press Enter. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms03 >> \u001b[0m");

// s04_hooks/Program.cs -- Hook System
//
// "Hook around the loop, never rewrite the loop" — extension points live
// on the HookBus, not in AgentHarness body.
//
// All hooks are declared in appsettings.json (the `hooks` section) and
// loaded dynamically at startup via agent.Hooks.ConfigureExternal(...).
// This file does not register a single OnXxx handler: the agent loop is
// untouched, every behavior comes from the configuration.

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Hooks;
using AgentCommon.Llm;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);
var tools = new ToolRegistry();

var workDir = ResolveWorkDir();
BashTool.Register(tools, workDir);
FileTools.Register(tools, workDir);

static string ResolveWorkDir()
{
    var cwd = Directory.GetCurrentDirectory();
    if (Directory.Exists(Path.Combine(cwd, "hooks"))) return cwd;

    var dir = AppContext.BaseDirectory;
    while (!string.IsNullOrEmpty(dir))
    {
        if (Directory.Exists(Path.Combine(dir, "hooks"))) return dir;
        var parent = Directory.GetParent(dir);
        if (parent is null || parent.FullName == dir) break;
        dir = parent.FullName;
    }
    return cwd;
}

var system = $"You are a coding agent at {workDir}. Use tools to solve tasks. Act, don't explain.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, tools, system)
{
    OnLog = Console.WriteLine,
    WorkDir = workDir,
    Permissions = new AllowAllPermissions(),
};

// One log file per day, written into <workDir>/logs/. Wired into the
// ExternalHookRunner so every hook invocation produces a structured
// before/after entry in the daily log.
using var logger = new AppLogger(workDir);
logger.Info("host", $"s04 starting in {workDir}");

// Load every external hook declared under `hooks.<Event>[]` in
// appsettings.json. The runner, work dir, and command list are all set
// from configuration; nothing is hard-coded below this line.
var n = agent.Hooks.ConfigureExternal(
    config.Hooks,
    workDir,
    log: msg => Console.Error.WriteLine(msg),
    timeout: TimeSpan.FromSeconds(30),
    logger: logger);
if (n > 0) Console.WriteLine($"[host] loaded {n} external hook(s) from appsettings.json");
Console.WriteLine($"[host] logging to {logger.CurrentFile}");

Console.WriteLine("s04: Hooks — all behavior from appsettings.json, loop untouched");
Console.WriteLine("Type a task and press Enter. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms04 >> \u001b[0m");
logger.Info("host", "s04 stopped");

// s05_todo_write/Program.cs -- TodoWrite
//
// "An agent without a plan drifts" — make the model maintain a todo list
// while it works, and nag it back to the list if it forgets.
//
// Compared to s04:
//   + TodoTools  (NEW: a tool the model calls to publish its plan)
//   + Nag counter (PostToolUse hook resets on todo_write, fires reminder
//                   on the next iteration if 3 rounds pass without one)

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Messages;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);
var tools = new ToolRegistry();

var workDir = Directory.GetCurrentDirectory();
BashTool.Register(tools, workDir);                    // from s01
FileTools.Register(tools, workDir);                   // from s02
var todos = new TodoTools.TodoState();
TodoTools.Register(tools, todos);                     // NEW in s05

var system = $"You are a coding agent at {workDir}. Use tools to solve tasks. Act, don't explain.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, tools, system)
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
};

// s05: nag reminder — runs as a Stop-style "force continue" with a user message
// every 3 rounds if the model has not called todo_write
var roundsSinceTodo = 0;
agent.Hooks.OnPostToolUse((block, _) =>
{
    if (block.Name == "todo_write")
    {
        roundsSinceTodo = 0;
    }
});
agent.Hooks.OnStop((IReadOnlyList<Message>? history) =>
{
    if (++roundsSinceTodo >= 3 && history is { Count: > 0 })
    {
        // Re-inject the last user message with a reminder nudge
        roundsSinceTodo = 0;
        return "<reminder>Update your todo list.</reminder>";
    }
    return null;
});

// Minimal hook log for s05
agent.Hooks.OnUserPromptSubmit(_ =>
    Console.WriteLine($"\u001b[90m[HOOK] UserPromptSubmit: cwd={workDir}\u001b[0m"));
agent.Hooks.OnPreToolUse(block =>
{
    var args = string.Join(", ", block.Input.EnumerateObject().Take(2).Select(o => $"{o.Name}={Trunc(o.Value.ToString())}"));
    Console.WriteLine($"\u001b[90m[HOOK] {block.Name}({args})\u001b[0m");
    return null;
});

Console.WriteLine("s05: TodoWrite — plan first, nag if you forget");
Console.WriteLine("Type a task and press Enter. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms05 >> \u001b[0m");

static string Trunc(string s) => s.Length > 60 ? s[..60] + "..." : s;

// s06_subagent/Program.cs -- Subagent
//
// "Big tasks split small, each subtask gets clean context" — the model
// can call `task` to launch a sub-agent. The sub-agent runs with a fresh
// message list and a trimmed tool set (no `task` itself, to prevent
// recursive spawning), and only the final text returns to the parent.

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Subagent;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);

var workDir = Directory.GetCurrentDirectory();

// ── Parent tools ─────────────────────────────────────────
var parentTools = new ToolRegistry();
BashTool.Register(parentTools, workDir);
FileTools.Register(parentTools, workDir);
var todos = new TodoTools.TodoState();
TodoTools.Register(parentTools, todos);

// ── Sub-agent tools (no `task` to prevent recursion) ────
var subTools = new ToolRegistry();
BashTool.Register(subTools, workDir);
FileTools.Register(subTools, workDir);

// ── Sub-agent factory: returns a SubagentRunner that runs the
//    shared loop with the sub-tool set and a sub-system prompt. ──
SubagentRunner SpawnSub() => new(
    client, config, subTools,
    $"You are a focused sub-agent at {workDir} on {HostEnvironment.OsName} ({HostEnvironment.Shell}). " +
    "Complete the given task and return a concise final answer.\n\n" +
    HostEnvironment.PromptFragment,
    msg => Console.WriteLine(msg));

// Register `task` tool on the parent
TaskTool.Register(parentTools, SpawnSub);

var system = $"You are a coding agent at {workDir}. Use tools to solve tasks. Act, don't explain. " +
             "Delegate focused subtasks via the `task` tool.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, parentTools, system)
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
};

// Minimal hook log
agent.Hooks.OnUserPromptSubmit(_ =>
    Console.WriteLine($"\u001b[90m[HOOK] UserPromptSubmit: cwd={workDir}\u001b[0m"));
agent.Hooks.OnPreToolUse(block =>
{
    var args = string.Join(", ", block.Input.EnumerateObject().Take(2).Select(o => $"{o.Name}={Trunc(o.Value.ToString())}"));
    Console.WriteLine($"\u001b[90m[HOOK] {block.Name}({args})\u001b[0m");
    return null;
});

Console.WriteLine("s06: Subagent — `task` tool spawns focused sub-agents");
Console.WriteLine("Type a task and press Enter. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms06 >> \u001b[0m");

static string Trunc(string s) => s.Length > 60 ? s[..60] + "..." : s;

// s07_skill_loading/Program.cs -- Skill Loading
//
// "Load knowledge on demand, not upfront" — two-level injection:
//
//   Layer 1 (cheap, always present): the system prompt carries the skill
//          catalog — name + one-line description per skill.
//
//   Layer 2 (expensive, on demand): the model calls load_skill(name)
//          to get the full SKILL.md content via the tool result.
//
// Compared to s06:
//   + SkillRegistry scans ../skills/ at startup
//   + build_system() injects the catalog into SYSTEM
//   + load_skill(name) returns the full SKILL.md

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Skills;
using AgentCommon.Subagent;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);

var workDir = Directory.GetCurrentDirectory();
var projectDir = AgentConfigLoader.ResolveProjectDir() ?? workDir;
var skillsDir = Path.GetFullPath(Path.Combine(projectDir, "..", "skills"));
var skills = SkillRegistry.LoadFromDir(skillsDir);

// ── Parent tools ─────────────────────────────────────────
var parentTools = new ToolRegistry();
BashTool.Register(parentTools, workDir);
FileTools.Register(parentTools, workDir);
var todos = new TodoTools.TodoState();
TodoTools.Register(parentTools, todos);
SkillTools.Register(parentTools, skills);  // NEW in s07

// Sub-agent gets a stripped-down view: no skill loading, no task
var subTools = new ToolRegistry();
BashTool.Register(subTools, workDir);
FileTools.Register(subTools, workDir);

SubagentRunner SpawnSub() => new(
    client, config, subTools,
    $"You are a focused sub-agent at {workDir} on {HostEnvironment.OsName} ({HostEnvironment.Shell}). " +
    "Complete the given task and return a concise final answer.\n\n" +
    HostEnvironment.PromptFragment,
    msg => Console.WriteLine(msg));
TaskTool.Register(parentTools, SpawnSub);

var system =
    $"You are a coding agent at {workDir}. " +
    "Skills available:\n" + skills.Catalog() + "\n" +
    "Use load_skill to get full details when needed.\n\n" +
    HostEnvironment.PromptFragment;

var agent = new AgentHarness(client, parentTools, system)
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
};

agent.Hooks.OnUserPromptSubmit(_ =>
    Console.WriteLine($"\u001b[90m[HOOK] UserPromptSubmit: cwd={workDir}\u001b[0m"));
agent.Hooks.OnPreToolUse(block =>
{
    var args = string.Join(", ", block.Input.EnumerateObject().Take(2).Select(o => $"{o.Name}={Trunc(o.Value.ToString())}"));
    Console.WriteLine($"\u001b[90m[HOOK] {block.Name}({args})\u001b[0m");
    return null;
});

Console.WriteLine("s07: Skill Loading — catalog in SYSTEM, full content on demand");
Console.WriteLine("Type a task and press Enter. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms07 >> \u001b[0m");

static string Trunc(string s) => s.Length > 60 ? s[..60] + "..." : s;

// s08_context_compact/Program.cs -- Context Compact
//
// "Context always fills up -- have a way to make room" — four-layer
// compaction pipeline inserted before every LLM call.
//
//   L1: SnipCompact       — trim middle messages when count > 50
//   L2: MicroCompact      — replace old tool_results with placeholders
//   L3: ToolResultBudget  — persist large results to disk
//   L4: CompactHistory    — LLM full summary (1 API call)
//
// Plus an emergency reactive path for prompt_too_long errors.
//
// Compared to s07:
//   + ContextCompactor  (the four layers, plus emergency reactive path)
//   + IContextCompactor plugged into AgentHarness.Compactor
//   Sub-agent, skills, todo_write, hooks: all unchanged from s07.

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Compact;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Skills;
using AgentCommon.Subagent;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);

var workDir = Directory.GetCurrentDirectory();
var skillsDir = Path.GetFullPath(Path.Combine(workDir, "..", "skills"));
var skills = SkillRegistry.LoadFromDir(skillsDir);

var parentTools = new ToolRegistry();
BashTool.Register(parentTools, workDir);
FileTools.Register(parentTools, workDir);
var todos = new TodoTools.TodoState();
TodoTools.Register(parentTools, todos);
SkillTools.Register(parentTools, skills);

var subTools = new ToolRegistry();
BashTool.Register(subTools, workDir);
FileTools.Register(subTools, workDir);

SubagentRunner SpawnSub() => new(
    client, config, subTools,
    $"You are a focused sub-agent at {workDir} on {HostEnvironment.OsName} ({HostEnvironment.Shell}). " +
    "Complete the given task and return a concise final answer.\n\n" +
    HostEnvironment.PromptFragment,
    msg => Console.WriteLine(msg));
TaskTool.Register(parentTools, SpawnSub);

var system =
    $"You are a coding agent at {workDir}. " +
    "Skills available:\n" + skills.Catalog() + "\n" +
    "Use load_skill to get full details when needed.\n\n" +
    HostEnvironment.PromptFragment;

// NEW in s08: the four-layer compactor
var compactor = new ContextCompactor(client, config, workDir, msg => Console.WriteLine(msg));

var agent = new AgentHarness(client, parentTools, system)
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
    Compactor = compactor,
};

agent.Hooks.OnUserPromptSubmit(_ =>
    Console.WriteLine($"\u001b[90m[HOOK] UserPromptSubmit: cwd={workDir}\u001b[0m"));
agent.Hooks.OnPreToolUse(block =>
{
    var args = string.Join(", ", block.Input.EnumerateObject().Take(2).Select(o => $"{o.Name}={Trunc(o.Value.ToString())}"));
    Console.WriteLine($"\u001b[90m[HOOK] {block.Name}({args})\u001b[0m");
    return null;
});

Console.WriteLine("s08: Context Compact — four layers, cheap first, expensive last");
Console.WriteLine("Type a long conversation and watch the compactor kick in. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms08 >> \u001b[0m");

static string Trunc(string s) => s.Length > 60 ? s[..60] + "..." : s;

// s09_memory/Program.cs -- Memory System
//
// "Remember what matters, forget what doesn't" — three subsystems:
//
//   selection    : pick relevant memories for the current context
//   extraction   : write new memories from recent dialogue
//   consolidation: merge/dedupe when count exceeds a threshold
//
// Compared to s08:
//   + MemoryStore, MemorySelector, MemoryExtractor, MemoryConsolidator
//   + PreToolUse hook injects selected memories
//   + PostToolUse hook extracts new memories and may consolidate
//   + SYSTEM carries the MEMORY.md index

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Compact;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Memory;
using AgentCommon.Messages;
using AgentCommon.Skills;
using AgentCommon.Subagent;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);

var workDir = Directory.GetCurrentDirectory();
var skillsDir = Path.GetFullPath(Path.Combine(workDir, "..", "skills"));
var skills = SkillRegistry.LoadFromDir(skillsDir);

var parentTools = new ToolRegistry();
BashTool.Register(parentTools, workDir);
FileTools.Register(parentTools, workDir);
var todos = new TodoTools.TodoState();
TodoTools.Register(parentTools, todos);
SkillTools.Register(parentTools, skills);

var subTools = new ToolRegistry();
BashTool.Register(subTools, workDir);
FileTools.Register(subTools, workDir);

SubagentRunner SpawnSub() => new(
    client, config, subTools,
    $"You are a focused sub-agent at {workDir} on {HostEnvironment.OsName} ({HostEnvironment.Shell}). " +
    "Complete the given task and return a concise final answer.\n\n" +
    HostEnvironment.PromptFragment,
    msg => Console.WriteLine(msg));
TaskTool.Register(parentTools, SpawnSub);

var store = new MemoryStore(workDir);
var selector = new MemorySelector(client, store);
var extractor = new MemoryExtractor(client, store, msg => Console.WriteLine(msg));
var consolidator = new MemoryConsolidator(client, store, threshold: 10, msg => Console.WriteLine(msg));

var system =
    $"You are a coding agent at {workDir}.\n\n" +
    "Memories available:\n" + (string.IsNullOrEmpty(store.IndexText()) ? "(none yet)" : store.IndexText()) + "\n\n" +
    "Relevant memories are injected below. Respect user preferences from memory.\n" +
    "When the user says 'remember' or expresses a clear preference, extract it as a memory.\n\n" +
    HostEnvironment.PromptFragment;

var compactor = new ContextCompactor(client, config, workDir, msg => Console.WriteLine(msg));
var agent = new AgentHarness(client, parentTools, system)
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
    Compactor = compactor,
};

agent.Hooks.OnUserPromptSubmit(_ =>
    Console.WriteLine($"\u001b[90m[HOOK] UserPromptSubmit: cwd={workDir}\u001b[0m"));
agent.Hooks.OnPreToolUse(block =>
{
    var args = string.Join(", ", block.Input.EnumerateObject().Take(2).Select(o => $"{o.Name}={Trunc(o.Value.ToString())}"));
    Console.WriteLine($"\u001b[90m[HOOK] {block.Name}({args})\u001b[0m");
    return null;
});

// Memory hooks
agent.Hooks.OnPreToolUse(block =>
{
    // Only run on the first LLM call of an iteration: skip on subsequent tool calls
    if (block.Name == "bash" || block.Name == "read_file" || block.Name == "glob" || block.Name == "edit_file" || block.Name == "write_file" || block.Name == "task" || block.Name == "todo_write" || block.Name == "load_skill")
    {
        return null; // do nothing here — selection happens via the Stop hook below
    }
    return null;
});

agent.Hooks.OnStop((IReadOnlyList<Message>? history) =>
{
    if (history is null || history.Count == 0) return null;
    _ = Task.Run(async () =>
    {
        // Selection: find relevant memories and surface them via console
        var selected = await selector.SelectRelevantAsync(history);
        if (selected.Count > 0)
        {
            Console.WriteLine($"\u001b[36m[Memory: selected {selected.Count}]\u001b[0m");
            foreach (var f in selected) Console.WriteLine($"  - {f}");
        }
        // Extraction: try to extract from the recent turn
        var extracted = await extractor.ExtractFromAsync(history);
        // Dream: consolidate if too many
        if (extracted > 0 || store.List().Count >= 10)
        {
            await consolidator.ConsolidateIfNeededAsync();
        }
    });
    return null;
});

Console.WriteLine("s09: Memory — selection, extraction, consolidation");
Console.WriteLine("Type a task and watch memories accumulate in .memory/. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms09 >> \u001b[0m");

static string Trunc(string s) => s.Length > 60 ? s[..60] + "..." : s;

// s10_system_prompt/Program.cs -- System Prompt
//
// "Prompts are assembled at runtime, not hardcoded" — section-keyed
// fragments joined by current context, with a deterministic cache.
//
// Compared to s09:
//   + PROMPT_SECTIONS: topic-keyed dict of prompt fragments
//   + assemble_system_prompt(context): select + join sections by real state
//   + get_system_prompt(context): deterministic cache (re-assembles only
//     when the context changes)
//   + update_context: derive context from real state on disk
//   The loop calls provider(context) before each LLM call, so sections
//   like 'memory' are picked up the moment a memory file appears.

using System.Text.Json;
using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Memory;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);

var workDir = Directory.GetCurrentDirectory();
var tools = new ToolRegistry();
BashTool.Register(tools, workDir);
FileTools.Register(tools, workDir);

var store = new MemoryStore(workDir);
var indexPath = Path.Combine(store.MemoryDir, "MEMORY.md");

// ── Prompt sections ────────────────────────────────────
var sections = new Dictionary<string, string>
{
    ["identity"] = "You are a coding agent. Act, don't explain.",
    ["tools"] = "Available tools: bash, read_file, write_file, edit_file, glob.",
    ["workspace"] = $"Working directory: {workDir}",
    ["memory"] = "Relevant memories are injected below when available.",
    ["environment"] = HostEnvironment.PromptFragment,
};

var assemble = (Dictionary<string, object> ctx) =>
{
    var parts = new List<string> { sections["identity"], sections["tools"], sections["workspace"], sections["environment"] };
    if (ctx.TryGetValue("memories", out var m) && m is string ms && !string.IsNullOrEmpty(ms))
    {
        parts.Add($"Relevant memories:\n{ms}");
    }
    return string.Join("\n\n", parts);
};

string? lastKey = null;
string? lastPrompt = null;
var getPrompt = (Dictionary<string, object> ctx) =>
{
    var key = JsonSerializer.Serialize(ctx, new JsonSerializerOptions
    {
        WriteIndented = false,
    });
    if (key == lastKey && lastPrompt is not null)
    {
        Console.WriteLine("  \u001b[90m[cache hit] system prompt unchanged\u001b[0m");
        return lastPrompt;
    }
    lastKey = key;
    lastPrompt = assemble(ctx);
    var loaded = new List<string> { "identity", "tools", "workspace", "environment" };
    if (ctx.TryGetValue("memories", out var m) && m is string ms && !string.IsNullOrEmpty(ms))
    {
        loaded.Add("memory");
    }
    Console.WriteLine($"  \u001b[32m[assembled] sections: {string.Join(", ", loaded)}\u001b[0m");
    Console.WriteLine("------ System Prompt -------");
    Console.WriteLine(lastPrompt);
    Console.WriteLine("----------------------------");
    return lastPrompt;
};

var updateContext = () =>
{
    var memIndex = File.Exists(indexPath) ? File.ReadAllText(indexPath).Trim() : "";
    return new Dictionary<string, object>
    {
        ["enabled_tools"] = tools.All().Select(t => t.Name).ToList(),
        ["workspace"] = workDir,
        ["memories"] = memIndex,
    };
};

var ctx = updateContext();
var agent = new AgentHarness(client, tools, () => getPrompt(ctx))
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
};
agent.Hooks.OnPreToolUse(block =>
{
    ctx = updateContext();
    return null;
});

Console.WriteLine("s10: System Prompt — runtime assembly with deterministic cache");
Console.WriteLine("Type a task and watch the system prompt cache log. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms10 >> \u001b[0m");

// s11_error_recovery/Program.cs -- Error Recovery
//
// "Errors aren't the end, they're the start of a retry" — three recovery
// paths wrapped around the LLM call:
//
//   1. max_tokens:           escalate 8K -> 64K, then a continuation nudge
//   2. prompt_too_long:      emergency compact -> retry
//   3. 429 / 529 overloaded: exponential backoff with jitter, fallback
//                            model on consecutive 529s
//
// Compared to s10:
//   + RetryPolicy attached to DeepSeekClient
//   + MaxTokensEscalation property on AgentHarness
//   + Emergency compact is exposed via IContextCompactor (s08)
//
// This chapter intentionally keeps the working toolset small so the
// focus is on the recovery paths.

using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Compact;
using AgentCommon.Config;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);

// NEW in s11: attach a retry policy (exponential backoff + fallback model)
client.AttachRetryPolicy(new RetryPolicy
{
    MaxRetries = 10,
    BaseDelayMs = 500,
    MaxConsecutiveOverloaded = 3,
    FallbackModel = config.FallbackModel,
    OnLog = msg => Console.WriteLine(msg),
});

var workDir = Directory.GetCurrentDirectory();
var tools = new ToolRegistry();
BashTool.Register(tools, workDir);
FileTools.Register(tools, workDir);

var compactor = new ContextCompactor(client, config, workDir, msg => Console.WriteLine(msg));

var system = $"You are a coding agent at {workDir}. Use tools to solve tasks. Act, don't explain.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, tools, system)
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
    Compactor = compactor,
    // Escalation target: 64K
    MaxTokensEscalation = 64_000,
};

agent.Hooks.OnUserPromptSubmit(_ =>
    Console.WriteLine($"\u001b[90m[HOOK] UserPromptSubmit: cwd={workDir}\u001b[0m"));
agent.Hooks.OnPreToolUse(block =>
{
    var args = string.Join(", ", block.Input.EnumerateObject().Take(2).Select(o => $"{o.Name}={Trunc(o.Value.ToString())}"));
    Console.WriteLine($"\u001b[90m[HOOK] {block.Name}({args})\u001b[0m");
    return null;
});

Console.WriteLine("s11: Error Recovery — backoff, escalation, fallback");
Console.WriteLine("Type a task. Set FALLBACK_MODEL_ID in appsettings.json to enable model fallback. Type q to quit.\n");
