// s18_worktree_isolation/Program.cs -- Worktree Isolation
//
// "Each works in its own directory, no interference" — every owned
// task gets a dedicated working directory under .worktrees/<name>.
// The teammate's bash tool, file reads/writes, etc. all run in that
// subdirectory, so two workers never clobber each other.
//
// Compared to s17:
//   + WorktreeRegistry: creates / removes / lists isolated directories
//   + TaskStore gains a worktree field
//   + TeammateRunner routes all tool work into the worktree dir
//   + Scout binds a worktree to each task it claims
//
// Note: the teaching version uses plain subdirectories, not git
// worktrees, so the lesson works without a git repository. The
// production equivalent binds .worktrees/<name> to a git worktree.

using System.Text.Json;
using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Background;
using AgentCommon.Compact;
using AgentCommon.Config;
using AgentCommon.Cron;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Messages;
using AgentCommon.Tasks;
using AgentCommon.Teams;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);

var workDir = Directory.GetCurrentDirectory();
var worktreesDir = Path.Combine(workDir, ".worktrees");
Directory.CreateDirectory(worktreesDir);

var tools = new ToolRegistry();

var background = new BackgroundRunner();
BashTool.Register(tools, workDir, onLog: msg => Console.WriteLine(msg), background: background);
FileTools.Register(tools, workDir);

var store = new TaskStore(workDir);
TaskTools.Register(tools, store, msg => Console.WriteLine(msg));

var cron = new CronScheduler(workDir, msg => Console.WriteLine(msg));
CronTools.Register(tools, cron);

var bus = new MessageBus(workDir, msg => Console.WriteLine(msg));
TeamTools.Register(tools, bus, client, config, workDir, msg => Console.WriteLine(msg));

// ── Worktree registry ───────────────────────────────────
var worktrees = new System.Collections.Concurrent.ConcurrentDictionary<string, string>();

string ValidateName(string name) =>
    System.Text.RegularExpressions.Regex.IsMatch(name, @"^[a-zA-Z0-9_\-]{1,32}$")
        ? name
        : throw new ArgumentException("Invalid worktree name (alphanumeric, dash, underscore; <=32 chars)");

tools.Register("create_worktree", "Create an isolated working directory and bind it to a task.",
    SchemaBuilder.Object("Create an isolated working directory and bind it to a task.",
        new Dictionary<string, (string, string, bool)>
        {
            ["name"] = ("string", "Short identifier (alphanumeric)", true),
            ["task_id"] = ("string", "Task ID to bind this worktree to", false),
        }),
    input =>
    {
        var name = ValidateName(input.GetProperty("name").GetString() ?? "");
        var path = Path.Combine(worktreesDir, name);
        if (worktrees.ContainsKey(name)) return $"Error: worktree '{name}' already exists";
        Directory.CreateDirectory(path);
        worktrees[name] = path;
        if (input.TryGetProperty("task_id", out var tid) && tid.ValueKind == JsonValueKind.String)
        {
            var id = tid.GetString() ?? "";
            try
            {
                var task = store.Load(id);
                // Stash worktree reference in the task description for visibility
                task.Description = string.IsNullOrEmpty(task.Description)
                    ? $"(worktree: {name})"
                    : $"{task.Description}\n(worktree: {name})";
                store.Save(task);
            }
            catch { /* task may not exist yet */ }
        }
        return $"Created worktree '{name}' at {path}";
    });

tools.Register("remove_worktree", "Remove an isolated working directory.",
    SchemaBuilder.Object("Remove an isolated working directory.",
        new Dictionary<string, (string, string, bool)>
        {
            ["name"] = ("string", "Worktree name", true),
            ["force"] = ("boolean", "Force removal even if not empty (default false)", false),
        }),
    input =>
    {
        var name = input.GetProperty("name").GetString() ?? "";
        if (!worktrees.TryRemove(name, out var path)) return $"Error: worktree '{name}' not found";
        var force = input.TryGetProperty("force", out var f) && f.ValueKind == JsonValueKind.True;
        if (Directory.Exists(path) && Directory.EnumerateFileSystemEntries(path).Any() && !force)
            return $"Error: worktree '{name}' not empty; pass force=true";
        if (Directory.Exists(path)) Directory.Delete(path, recursive: true);
        return $"Removed worktree '{name}'";
    });

tools.Register("list_worktrees", "List all worktrees.", SchemaBuilder.Object("List all worktrees.",
    new Dictionary<string, (string, string, bool)>()),
    _ => worktrees.Count == 0
        ? "(no worktrees)"
        : string.Join("\n", worktrees.Select(kv => $"- {kv.Key} -> {kv.Value}")));

// ── Scout that picks tasks, creates a worktree, spawns a worker
//    scoped to that worktree.
var cts = new CancellationTokenSource();
var scout = new Thread(async () =>
{
    while (!cts.IsCancellationRequested)
    {
        try
        {
            var candidate = store.List().FirstOrDefault(t =>
                t.Status == "pending"
                && string.IsNullOrEmpty(t.Owner)
                && store.CanStart(t));
            if (candidate is not null)
            {
                var wtName = $"wt_{candidate.Id.Replace("task_", "")}";
                try { ValidateName(wtName); } catch { wtName = wtName.Replace("-", "_"); }
                var wtPath = Path.Combine(worktreesDir, wtName);
                Directory.CreateDirectory(wtPath);
                worktrees[wtName] = wtPath;

                store.Claim(candidate.Id, owner: wtName);

                var name = $"worker_{candidate.Id}";
                var prompt = $"Take ownership of task {candidate.Id}: {candidate.Subject}. " +
                             $"Work inside {wtPath}. Complete it and report back.";
                var runner = new TeammateRunner(client, config, wtPath, bus, name, "worker",
                    onLog: msg => Console.WriteLine(msg), maxRounds: 12);
                var t = new Thread(async () =>
                {
                    try { await runner.RunAsync(prompt, cts.Token); }
                    finally
                    {
                        var (ok, _, _) = store.Complete(candidate.Id);
                        if (ok) Console.WriteLine($"\u001b[32m[scout] auto-completed {candidate.Id}\u001b[0m");
                    }
                }) { IsBackground = true, Name = name };
                t.Start();
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"\u001b[31m[scout] {ex.GetType().Name}: {ex.Message}\u001b[0m");
        }
        try { await Task.Delay(TimeSpan.FromSeconds(5), cts.Token); } catch { break; }
    }
}) { IsBackground = true, Name = "worktree-scout" };
scout.Start();

var compactor = new ContextCompactor(client, config, workDir, msg => Console.WriteLine(msg));
var system = $"You are the lead coding agent at {workDir}. " +
             "Create tasks; the scout will create a worktree and spawn a worker for each.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, tools, system)
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
    Compactor = compactor,
    MaxTokensEscalation = config.MaxTokensEscalation,
};

agent.Hooks.OnBeforeLlmCall(messages =>
{
    var done = background.DrainCompleted();
    if (done.Count > 0)
        messages.Add(Message.UserText(background.FormatNotifications(done)));
    foreach (var j in cron.DrainQueue())
        messages.Add(Message.UserText($"<cron-fire id=\"{j.Id}\">{j.Prompt}</cron-fire>"));
    var inbox = bus.ReadInbox("lead");
    if (inbox.Count > 0)
        messages.Add(Message.UserText("<inbox>\n" + JsonSerializer.Serialize(inbox, new JsonSerializerOptions { WriteIndented = true }) + "\n</inbox>"));
});

Console.WriteLine("s18: Worktree Isolation — each task owns its directory");
Console.WriteLine("Type a task. The scout will create worktrees and dispatch workers. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms18 >> \u001b[0m");
cts.Cancel();

// s19_mcp_plugin/Program.cs -- MCP Plugin
//
// "Not enough capability? Plug in more via MCP" — tools from external
// MCP servers are combined with built-in tools into a single pool
// the model sees. Tool names are normalized as
// `mcp__{server}__{tool}`.
//
// The teaching implementation uses a hand-rolled mock MCP server
// (a static catalog of tools). The protocol structure is identical
// to the production MCP JSON-RPC pattern; only the transport
// (stdio / SSE) is replaced by an in-process dictionary.

using System.Text.Json;
using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Background;
using AgentCommon.Compact;
using AgentCommon.Config;
using AgentCommon.Cron;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Messages;
using AgentCommon.Tasks;
using AgentCommon.Teams;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);

var workDir = Directory.GetCurrentDirectory();
var builtin = new ToolRegistry();

var background = new BackgroundRunner();
BashTool.Register(builtin, workDir, onLog: msg => Console.WriteLine(msg), background: background);
FileTools.Register(builtin, workDir);

var store = new TaskStore(workDir);
TaskTools.Register(builtin, store, msg => Console.WriteLine(msg));

var cron = new CronScheduler(workDir, msg => Console.WriteLine(msg));
CronTools.Register(builtin, cron);

var bus = new MessageBus(workDir, msg => Console.WriteLine(msg));
TeamTools.Register(builtin, bus, client, config, workDir, msg => Console.WriteLine(msg));

// ── Mock MCP server: "docs" exposes two tools ───────────
var mockDocs = new Dictionary<string, Func<JsonElement, string>>(StringComparer.OrdinalIgnoreCase)
{
    ["search"] = input =>
    {
        var q = input.TryGetProperty("query", out var qp) ? qp.GetString() ?? "" : "";
        return $"docs.search(\"{q}\") — would call an external docs service (mocked).";
    },
    ["get_version"] = _ => "docs.get_version: 1.0.0 (mocked)",
};
var mockFs = new Dictionary<string, Func<JsonElement, string>>(StringComparer.OrdinalIgnoreCase)
{
    ["list_dir"] = input =>
    {
        var p = input.TryGetProperty("path", out var pp) ? pp.GetString() ?? "." : ".";
        try
        {
            var full = Path.IsPathRooted(p) ? p : Path.Combine(workDir, p);
            return string.Join("\n", Directory.EnumerateFileSystemEntries(full).Select(Path.GetFileName));
        }
        catch (Exception ex) { return $"Error: {ex.Message}"; }
    },
};

var serverTools = new Dictionary<string, (Dictionary<string, Func<JsonElement, string>> catalog, string connection)>(StringComparer.OrdinalIgnoreCase)
{
    ["docs"] = (mockDocs, "stdio://docs-server"),
    ["fs"] = (mockFs, "stdio://fs-server"),
};

string Normalize(string s) => System.Text.RegularExpressions.Regex.Replace(s.ToLowerInvariant(), @"[^a-z0-9_]+", "_");

// ── Pool = builtin ∪ MCP ────────────────────────────────
var pool = new ToolRegistry();
foreach (var t in builtin.All()) pool.Register(t.Name, t.Description, t.InputSchema, t.Handler);
foreach (var (server, (catalog, conn)) in serverTools)
{
    foreach (var toolName in catalog.Keys)
    {
        var localCatalog = catalog;
        var prefix = $"mcp__{Normalize(server)}__{Normalize(toolName)}";
        var schema = SchemaBuilder.Object($"MCP tool {toolName} on {server}.",
            new Dictionary<string, (string, string, bool)>());
        pool.Register(prefix, $"MCP tool {toolName} on {server}.", schema, input =>
            localCatalog[toolName](input));
    }
}

Console.WriteLine($"\u001b[36m[s19] tool pool assembled: {pool.All().Count()} tools ({serverTools.Sum(kv => kv.Value.catalog.Count)} MCP, {builtin.All().Count()} builtin)\u001b[0m");

var compactor = new ContextCompactor(client, config, workDir, msg => Console.WriteLine(msg));
var system = $"You are a coding agent at {workDir}. " +
             $"Available tools: {string.Join(", ", pool.All().Select(t => t.Name))}.\n\n" +
             HostEnvironment.PromptFragment;
var agent = new AgentHarness(client, pool, system)
{
    OnLog = Console.WriteLine,
    Permissions = new AllowAllPermissions(),
    Compactor = compactor,
    MaxTokensEscalation = config.MaxTokensEscalation,
};

agent.Hooks.OnUserPromptSubmit(_ =>
    Console.WriteLine($"\u001b[90m[HOOK] UserPromptSubmit: cwd={workDir}\u001b[0m"));
agent.Hooks.OnPreToolUse(block =>
{
    var args = string.Join(", ", block.Input.EnumerateObject().Take(2).Select(o => $"{o.Name}={Trunc(o.Value.ToString())}"));
    Console.WriteLine($"\u001b[90m[HOOK] {block.Name}({args})\u001b[0m");
    return null;
});
agent.Hooks.OnBeforeLlmCall(messages =>
{
    var done = background.DrainCompleted();
    if (done.Count > 0)
        messages.Add(Message.UserText(background.FormatNotifications(done)));
    foreach (var j in cron.DrainQueue())
        messages.Add(Message.UserText($"<cron-fire id=\"{j.Id}\">{j.Prompt}</cron-fire>"));
});

Console.WriteLine("s19: MCP Plugin — external tools merged into one pool");
Console.WriteLine("Type a task. The model sees builtins + mcp__* tools. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms19 >> \u001b[0m");

static string Trunc(string s) => s.Length > 60 ? s[..60] + "..." : s;

// s20_comprehensive/Program.cs -- Comprehensive Agent
//
// "Many mechanisms, one loop" — every prior mechanism is enabled at
// once. The harness's loop doesn't change; we just register every
// tool and every hook. This is what production looks like.
//
//   s01  Agent loop
//   s02  Tool use (file tools)
//   s03  Permission pipeline
//   s04  Hook system
//   s05  TodoWrite
//   s06  Subagent (task tool)
//   s07  Skill loading
//   s08  Context compact
//   s09  Memory
//   s10  System prompt assembly
//   s11  Error recovery
//   s12  Task system
//   s13  Background tasks
//   s14  Cron scheduler
//   s15  Agent teams
//   s16  Team protocols
//   s17  Autonomous agents
//   s18  Worktree isolation
//   s19  MCP plugin

using System.Text.Json;
using AgentCommon;
using AgentCommon.Agent;
using AgentCommon.Background;
using AgentCommon.Compact;
using AgentCommon.Config;
using AgentCommon.Cron;
using AgentCommon.Defaults;
using AgentCommon.Llm;
using AgentCommon.Memory;
using AgentCommon.Messages;
using AgentCommon.Permissions;
using AgentCommon.Skills;
using AgentCommon.Subagent;
using AgentCommon.Tasks;
using AgentCommon.Teams;
using AgentCommon.Tools;
using AgentCommon.Util;

HostEnvironment.Initialize();
Console.WriteLine($"[host] {HostEnvironment.OsName} ({HostEnvironment.Shell})");

var config = AgentConfigLoader.Load();
var client = new DeepSeekClient(config);
client.AttachRetryPolicy(new RetryPolicy
{
    FallbackModel = config.FallbackModel,
    OnLog = msg => Console.WriteLine(msg),
});

var workDir = Directory.GetCurrentDirectory();
var skillsDir = Path.GetFullPath(Path.Combine(workDir, "..", "skills"));
var skills = SkillRegistry.LoadFromDir(skillsDir);

var tools = new ToolRegistry();
var background = new BackgroundRunner();
BashTool.Register(tools, workDir, onLog: msg => Console.WriteLine(msg), background: background);
FileTools.Register(tools, workDir);
SkillTools.Register(tools, skills);

var todos = new TodoTools.TodoState();
TodoTools.Register(tools, todos);

var store = new TaskStore(workDir);
TaskTools.Register(tools, store, msg => Console.WriteLine(msg));

var cron = new CronScheduler(workDir, msg => Console.WriteLine(msg));
CronTools.Register(tools, cron);

var bus = new MessageBus(workDir, msg => Console.WriteLine(msg));
TeamTools.Register(tools, bus, client, config, workDir, msg => Console.WriteLine(msg));

// Sub-agent (uses its own stripped-down tool set)
var subTools = new ToolRegistry();
BashTool.Register(subTools, workDir, onLog: msg => Console.WriteLine(msg));
FileTools.Register(subTools, workDir);
SubagentRunner SpawnSub() => new(
    client, config, subTools,
    $"You are a focused sub-agent on {HostEnvironment.OsName} ({HostEnvironment.Shell}). " +
    "Return a concise summary.\n\n" + HostEnvironment.PromptFragment,
    msg => Console.WriteLine(msg));
TaskTool.Register(tools, SpawnSub);

// MCP tools (mock)
tools.Register("mcp__docs__search", "Search an external docs service.",
    SchemaBuilder.Object("Search an external docs service.",
        new Dictionary<string, (string, string, bool)> { ["query"] = ("string", "Search query", true) }),
    input => $"docs.search(\"{input.GetProperty("query").GetString()}\") — mocked MCP result");

// Memory + selection (hook-based)
var memStore = new MemoryStore(workDir);
var memSelector = new MemorySelector(client, memStore);
var memExtractor = new MemoryExtractor(client, memStore, msg => Console.WriteLine(msg));
var memConsolidator = new MemoryConsolidator(client, memStore, threshold: 10, msg => Console.WriteLine(msg));

// Permissions (s03)
var denyList = new[] { "rm -rf /", "sudo", "shutdown", "reboot", "mkfs", "dd if=", "> /dev/sda" };
var rules = new List<PermissionRule>
{
    new() { Tools = new[] { "write_file", "edit_file" },
            Check = args => { try { _ = PathGuard.SafePath(workDir, args.GetProperty("path").GetString() ?? ""); return null; } catch { return "Writing outside workspace"; } },
            Message = "Writing outside workspace" },
    new() { Tools = new[] { "bash" },
            Check = args => { var c = args.TryGetProperty("command", out var v) ? v.GetString() ?? "" : ""; return c.Contains("rm ", StringComparison.Ordinal) || c.Contains("> /etc/", StringComparison.Ordinal) ? "Potentially destructive command" : null; },
            Message = "Potentially destructive command" },
};
var permissions = new InteractivePermissionPipeline(workDir, denyList, rules);

// System prompt assembly (s10) — sections + cache
var sections = new Dictionary<string, string>
{
    ["identity"] = "You are a comprehensive coding agent with all mechanisms enabled.",
    ["tools"] = "Available tools: bash, read_file, write_file, edit_file, glob, todo_write, task, load_skill, create_task/list_tasks/claim_task/complete_task, schedule_cron/list_crons/cancel_cron, spawn_teammate/send_message/check_inbox, mcp__docs__search.",
    ["workspace"] = $"Working directory: {workDir}",
    ["memory"] = "Relevant memories are injected below when available.",
    ["environment"] = HostEnvironment.PromptFragment,
};
var ctx = new Dictionary<string, object>
{
    ["enabled_tools"] = tools.All().Select(t => t.Name).ToList(),
    ["workspace"] = workDir,
    ["memories"] = memStore.IndexText(),
};
string? lastKey = null, lastPrompt = null;
string GetPrompt()
{
    var key = JsonSerializer.Serialize(ctx);
    if (key == lastKey && lastPrompt is not null) return lastPrompt;
    lastKey = key; lastPrompt = Assemble(sections, ctx);
    return lastPrompt;
}

var compactor = new ContextCompactor(client, config, workDir, msg => Console.WriteLine(msg));
var agent = new AgentHarness(client, tools, (Func<string>)GetPrompt)
{
    OnLog = Console.WriteLine,
    Permissions = permissions,
    Compactor = compactor,
    MaxTokensEscalation = config.MaxTokensEscalation,
};

agent.Hooks.OnUserPromptSubmit(_ => Console.WriteLine($"\u001b[90m[HOOK] UserPromptSubmit\u001b[0m"));
agent.Hooks.OnPreToolUse(block =>
{
    var args = string.Join(", ", block.Input.EnumerateObject().Take(2).Select(o => $"{o.Name}={Trunc(o.Value.ToString())}"));
    Console.WriteLine($"\u001b[90m[HOOK] {block.Name}({args})\u001b[0m");
    return null;
});
agent.Hooks.OnBeforeLlmCall(messages =>
{
    var done = background.DrainCompleted();
    if (done.Count > 0)
        messages.Add(Message.UserText(background.FormatNotifications(done)));
    foreach (var j in cron.DrainQueue())
        messages.Add(Message.UserText($"<cron-fire id=\"{j.Id}\">{j.Prompt}</cron-fire>"));
    var inbox = bus.ReadInbox("lead");
    if (inbox.Count > 0)
        messages.Add(Message.UserText("<inbox>\n" + JsonSerializer.Serialize(inbox, new JsonSerializerOptions { WriteIndented = true }) + "\n</inbox>"));
    _ = memExtractor.ExtractFromAsync(messages).ContinueWith(t => memConsolidator.ConsolidateIfNeededAsync());
});

Console.WriteLine("s20: Comprehensive Agent — every mechanism, one loop");
Console.WriteLine("Bash, files, todo, skills, sub-agent, memory, compact, retry, tasks, background, cron, teams, MCP, hooks, permissions.");
Console.WriteLine("Type a complex task. Type q to quit.\n");
await Repl.RunAsync(agent, "\u001b[36ms20 >> \u001b[0m");

static string Assemble(Dictionary<string, string> sections, Dictionary<string, object> ctx)
{
    var parts = new List<string> { sections["identity"], sections["tools"], sections["workspace"], sections["environment"] };
    if (ctx.TryGetValue("memories", out var m) && m is string ms && !string.IsNullOrEmpty(ms))
        parts.Add($"Relevant memories:\n{ms}");
    return string.Join("\n\n", parts);
}

static string Trunc(string s) => s.Length > 60 ? s[..60] + "..." : s;
